package automation

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/automation"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/events"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type OnCommentReportProxy struct {
	automation.UnimplementedOnCommentReportServer
	client automation.OnCommentReportClient
}

func init() {
	proxyutil.Register(&automation.OnCommentReport_ServiceDesc, NewOnCommentReportProxy)
}
func NewOnCommentReportProxy(cc grpc.ClientConnInterface) automation.OnCommentReportServer {
	return &OnCommentReportProxy{client: automation.NewOnCommentReportClient(cc)}
}
func (p *OnCommentReportProxy) OnCommentReport(ctx context.Context, in *events.CommentReport) (*automation.HandlerResult, error) {
	return proxyutil.ProxyMethod[events.CommentReport, automation.HandlerResult](p.client.OnCommentReport)(ctx, in)
}
